mapper.select:
SELECT o.OUTBOUND_ID, o.PLANT_CD, o.OUTBOUND_NO, o.OUTBOUND_STATUS, o.CUSTOMER_CD, o.WAREHOUSE_CD, o.REQUEST_DT, o.SHIPPED_DT, o.DESTINATION, o.ISSUE_PLAN_ID, o.WO_ID, o.OUTBOUND_RMK, o.REG_USER_ID, o.REG_DTM, o.UPD_USER_ID, o.UPD_DTM, p.PLANT_NM, w.WAREHOUSE_NM, c.COM_NM AS OUTBOUND_STATUS_NM FROM MCS_OUTBOUND_ORDER o INNER JOIN MST_PLANT p ON o.PLANT_CD = p.PLANT_CD LEFT JOIN MST_WAREHOUSE w ON o.WAREHOUSE_CD = w.WAREHOUSE_CD LEFT JOIN COM_CODE c ON c.GRP_CD = 'MCS_OB_STATUS' AND o.OUTBOUND_STATUS = c.COM_CD
AND o.PLANT_CD = #{plantCd} AND o.WAREHOUSE_CD = #{warehouseCd} AND o.OUTBOUND_STATUS = #{outboundStatus} AND o.OUTBOUND_NO LIKE CONCAT('%', #{outboundNo}, '%') AND o.REQUEST_DT >= CONCAT(#{fromDate}, ' 00:00:00') AND o.REQUEST_DT <= CONCAT(#{toDate}, ' 23:59:59')
ORDER BY o.REQUEST_DT DESC, o.OUTBOUND_NO DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM MCS_OUTBOUND_ORDER o

    AND o.PLANT_CD = #{plantCd}
    AND o.WAREHOUSE_CD = #{warehouseCd}
    AND o.OUTBOUND_STATUS = #{outboundStatus}
    AND o.OUTBOUND_NO LIKE CONCAT('%', #{outboundNo}, '%')
    AND o.REQUEST_DT >= CONCAT(#{fromDate}, ' 00:00:00')
    AND o.REQUEST_DT <= CONCAT(#{toDate}, ' 23:59:59')
